function requirement(input) {
  return Object.freeze({
    id: input.id,
    status: input.status,
    invariant: input.invariant,
    scope: input.scope,
    expectedInvariant: input.expectedInvariant,
    sourcePaths: Object.freeze(input.sourcePaths),
    existingEvidence: Object.freeze(input.existingEvidence),
    releaseRisk: input.releaseRisk,
    requiredProof: input.requiredProof,
    validationCommands: Object.freeze(input.validationCommands),
    stopConditions: Object.freeze([...COMMON_STOP_CONDITIONS, ...input.stopConditions]),
    releaseReadyClaim: false,
    finalValidationRequired: true,
  })
}

